if (!defined('CLI_SCRIPT')) { define('CLI_SCRIPT', true); }
require('/www/moodle/config.php');
require_once($CFG->dirroot . '/course/lib.php');
require_once($CFG->dirroot . '/mod/customcert/lib.php');
try {
    $course = $DB->get_record('course', ['shortname' => 'CCERTDEMO01'], '*', MUST_EXIST);
    $module = $DB->get_record('modules', ['name' => 'customcert'], '*', MUST_EXIST);
    $admin = get_admin();
    \core\session\manager::set_user($admin);
    $now = time();
    $cm = (object)[
        'course'       => $course->id,
        'module'       => $module->id,
        'instance'     => 0,
        'section'      => 1,
        'idnumber'     => '',
        'added'        => $now,
        'score'        => 0,
        'indent'       => 0,
        'visible'      => 1,
        'visibleold'   => 1,
        'groupmode'    => 0,
        'groupingid'   => 0,
        'completion'   => 0,
        'showdescription' => 0,
    ];
    $cmid = add_course_module($cm);
    course_add_cm_to_section($course->id, $cmid, 1);
    $data = (object)[
        'course'        => $course->id,
        'coursemodule'  => $cmid,
        'name'          => 'Sample certificate',
        'intro'         => '<p>Open this activity to try <strong>mod_customcert</strong>: edit the certificate template (add text / images / borders), then issue and download a PDF as the demo student.</p>',
        'introformat'   => FORMAT_HTML,
        'requiredtime'  => 0,
        'verifyany'     => 0,
        'deliveryoption'=> 'I',
        'protection_print'    => 0,
        'protection_modify'   => 0,
        'protection_copy'     => 0,
        'emailstudents' => 0,
        'emailteachers' => 0,
        'emailothers'   => '',
        'language'      => '',
    ];
    $instanceid = customcert_add_instance($data, null);
    $DB->set_field('course_modules', 'instance', $instanceid, ['id' => $cmid]);
    rebuild_course_cache($course->id, true);
    $cert = $DB->get_record('customcert', ['id' => $instanceid], '*', MUST_EXIST);
    $page = $DB->get_record('customcert_pages', ['templateid' => $cert->templateid], '*', IGNORE_MULTIPLE);
    if ($page) {
        $samples = [
            ['name' => 'Title',      'text' => 'Certificate of Completion',                       'fontsize' => 30, 'posy' => 50,  'colour' => '#1d3557'],
            ['name' => 'Subtitle',   'text' => 'This certificate is proudly presented to',         'fontsize' => 14, 'posy' => 90,  'colour' => '#333333'],
            ['name' => 'Recipient',  'text' => 'Demo Student',                                     'fontsize' => 24, 'posy' => 115, 'colour' => '#000000'],
            ['name' => 'Body',       'text' => 'for successfully completing the Moodle Playground demo course showcasing the mod_customcert activity.', 'fontsize' => 12, 'posy' => 145, 'colour' => '#333333'],
            ['name' => 'Footer',     'text' => 'Issued on the Moodle Playground preview',          'fontsize' => 10, 'posy' => 245, 'colour' => '#666666'],
        ];
        $seq = 0;
        foreach ($samples as $s) {
            $payload = ['text' => $s['text'], 'font' => 'freesans', 'fontsize' => $s['fontsize'], 'colour' => $s['colour'], 'width' => 170];
            $DB->insert_record('customcert_elements', (object)[
                'pageid'       => $page->id,
                'name'         => $s['name'],
                'element'      => 'text',
                'data'         => json_encode($payload),
                'posx'         => 20,
                'posy'         => $s['posy'],
                'refpoint'     => 0,
                'alignment'    => 'C',
                'sequence'     => $seq++,
                'timecreated'  => $now,
                'timemodified' => $now,
            ]);
        }
        echo "Seeded " . count($samples) . " text elements on page {$page->id}\n";
    }
    echo "Created mod_customcert instance id={$instanceid} cmid={$cmid} in course {$course->shortname}\n";
} catch (\Throwable $e) {
    echo 'ERROR: ' . $e->getMessage() . "\n";
}
